  ('public-health-specialist-moex-00017', 'public-health-specialist', 'public-health-specialist-moex-114-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '關於計畫內部評價和外部評價的描述，下列何者錯誤？', '["內部評價是指A團隊的人執行該計畫，且由A團隊的人來做計畫評價", "外部評價是請非計畫相關人員來進行計畫評價", "外部評價請的評價者通常對計畫很瞭解，能提供第三方較客觀的觀點", "內部評價的評價者通常因為是自己人，可能會有球員兼裁判的問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:34+00:00", "source_pdf_sha1": "007e33ed379e", "answer_pdf_sha1": "37ad037b45e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
